"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[76184],{70542(e,t,i){i.r(t),i.d(t,{assets:()=>d,contentTitle:()=>o,default:()=>l,frontMatter:()=>s,metadata:()=>a,toc:()=>c});let a=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 12 Income Taxes/deferred-tax-related-to-an-investmen-2726c9fd48","title":"Deferred Tax related to an Investment in a Subsidiary (IAS 12)","description":"June 2020","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 12 Income Taxes/Deferred Tax related to an Investment in a Subsidiary (IAS 12).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 12 Income Taxes","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/deferred-tax-related-to-an-investmen-2726c9fd48","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/deferred-tax-related-to-an-investmen-2726c9fd48","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"deferred-tax-related-to-an-investmen-2726c9fd48","title":"Deferred Tax related to an Investment in a Subsidiary (IAS 12)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/deferred-tax-related-to-an-investmen-2726c9fd48","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Preparation of Financial Statements when an Entity is No Longer a Going Concern (IAS 10)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-10-events-after-the-reporting-pe-4f7513b6f5/preparation-of-financial-statements--bff3247d2f"},"next":{"title":"Multiple Tax Consequences of Recovering an Asset (IAS 12)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/multiple-tax-consequences-of-recover-83d524c0ea"}}');var n=i(74848),r=i(28453);let s={id:"deferred-tax-related-to-an-investmen-2726c9fd48",title:"Deferred Tax related to an Investment in a Subsidiary (IAS 12)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-12-income-taxes-c46395e692/deferred-tax-related-to-an-investmen-2726c9fd48",sidebar_position:1},o="Deferred Tax related to an Investment in a Subsidiary (IAS 12)",d={},c=[];function f(e){let t={h1:"h1",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"deferred-tax-related-to-an-investment-in-a-subsidiary-ias-12",children:"Deferred Tax related to an Investment in a Subsidiary (IAS 12)"})}),"\n",(0,n.jsx)(t.p,{children:"June 2020"}),"\n",(0,n.jsx)(t.p,{children:"The Committee received a request about how an entity, in its consolidated financial statements, accounts for deferred tax related to its investment in a subsidiary. In the fact pattern described in the request:"}),"\n",(0,n.jsx)(t.p,{children:"a. undistributed profits of the subsidiary give rise to a taxable temporary difference associated with the entity\u2019s investment in the subsidiary.\nb. the entity has determined that the conditions in paragraph 39 of IAS 12 for applying the exception from recognising a deferred tax liability related to its investment in the subsidiary are not satisfied because the entity expects the subsidiary to distribute its profits (which are available for distribution) in the\nforeseeable future.\nc. the entity and subsidiary operate in a jurisdiction in which:\ni. profits are taxable only when distributed\u2014that is, the income tax rate applicable to undistributed profits is nil (undistributed tax rate).\nii. a 20% tax rate applies to profit distributions (distributed tax rate). However, profit distributions made by the entity are not taxable to the extent that the subsidiary has already been taxed on that profit\u2014that is, profit distributions are taxed only once."}),"\n",(0,n.jsx)(t.p,{children:"The request asked whether the entity recognises a deferred tax liability for the taxable temporary difference associated with its investment in the subsidiary."}),"\n",(0,n.jsx)(t.p,{children:"Paragraph 39 of IAS 12 requires an entity to recognise a deferred tax liability for all taxable temporary differences associated with investments in subsidiaries, except to the extent that (a) the parent is able to control the timing of the reversal of the temporary difference; and (b) it is probable that the temporary difference will not reverse in the foreseeable future."}),"\n",(0,n.jsx)(t.p,{children:"In the fact pattern described in the request, there is a taxable temporary difference associated with the entity\u2019s investment in the subsidiary. The entity has also determined that the recognition exception in paragraph 39 of IAS 12 does not apply because it is probable that the temporary difference will reverse in the foreseeable future when the subsidiary distributes its undistributed profits. Accordingly, the Committee concluded that the entity recognises a deferred tax liability for that taxable temporary difference."}),"\n",(0,n.jsx)(t.p,{children:"Paragraph 51 of IAS 12 requires an entity to reflect\u2014in the measurement of deferred tax assets and deferred tax liabilities\u2014'the tax consequences that would follow from the manner in which the entity expects, at the end of the reporting period, to recover or settle the carrying amount of its assets and liabilities\u2019."}),"\n",(0,n.jsx)(t.p,{children:"In the fact pattern described in the request, the entity expects to recover the carrying amount of its investment in the subsidiary through distributions of profits by the subsidiary, which would be taxed at the distributed tax rate. Accordingly, the Committee concluded that, in applying paragraph 51 of IAS 12, the entity uses the distributed tax rate to measure the deferred tax liability related to its investment in the subsidiary."}),"\n",(0,n.jsx)(t.p,{children:"The Committee observed that, in the fact pattern described in the request, the entity does not apply paragraph 57A of IAS 12\u2014that paragraph applies only in the context of dividends payable by the reporting entity. Further, paragraph 52A of IAS 12 does not apply to the measurement of a current or deferred tax asset or liability that itself reflects the tax consequences of a distribution of profits."}),"\n",(0,n.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IAS 12 provide an adequate basis for an entity to account for deferred tax in the fact pattern described in the request. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function l(e={}){let{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(f,{...e})}):f(e)}},28453(e,t,i){i.d(t,{R:()=>s,x:()=>o});var a=i(96540);let n={},r=a.createContext(n);function s(e){let t=a.useContext(r);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),a.createElement(r.Provider,{value:t},e.children)}}}]);